  1→import { randomBytes } from "node:crypto";
  2→import * as p from "@clack/prompts";
  3→import { buildCommand } from "@stricli/core";
  4→import { loadCredentials, saveCredentials } from "../lib/credentials.js";
  5→
  6→const DEFAULT_API_BASE = "https://app.rudel.ai";
  7→const DEFAULT_WEB_URL = "https://app.rudel.ai";
  8→const CALLBACK_TIMEOUT_MS = 120_000;
  9→
 10→async function runLogin(flags: {
 11→	apiBase: string;
 12→	webUrl: string;
 13→}): Promise<void> {
 14→	p.intro("rudel login");
 15→
 16→	const existing = loadCredentials();
 17→	if (existing) {
 18→		p.log.warn("Already logged in.");
 19→		p.outro("Run `rudel logout` first to switch accounts.");
 20→		return;
 21→	}
 22→
 23→	const state = randomBytes(16).toString("hex");
 24→
 25→	let resolveCallback: (token: string) => void;
 26→	let rejectCallback: (error: Error) => void;
 27→	const tokenPromise = new Promise<string>((resolve, reject) => {
 28→		resolveCallback = resolve;
 29→		rejectCallback = reject;
 30→	});
 31→
 32→	const server = Bun.serve({
 33→		port: 0,
 34→		hostname: "127.0.0.1",
 35→		fetch(request) {
 36→			const url = new URL(request.url);
 37→			if (url.pathname !== "/callback") {
 38→				return new Response("Not found", { status: 404 });
 39→			}
 40→
 41→			const receivedToken = url.searchParams.get("token");
 42→			const receivedState = url.searchParams.get("state");
 43→
 44→			if (receivedState !== state) {
 45→				rejectCallback(new Error("State mismatch — possible CSRF attack"));
 46→				return new Response(
 47→					"<html><body><h1>Login failed</h1><p>State mismatch. Please try again.</p></body></html>",
 48→					{ headers: { "Content-Type": "text/html" } },
 49→				);
 50→			}
 51→
 52→			if (!receivedToken) {
 53→				rejectCallback(new Error("No token received"));
 54→				return new Response(
 55→					"<html><body><h1>Login failed</h1><p>No token received.</p></body></html>",
 56→					{ headers: { "Content-Type": "text/html" } },
 57→				);
 58→			}
 59→
 60→			resolveCallback(receivedToken);
 61→			return new Response(
 62→				"<html><body><h1>Login successful!</h1><p>You can close this tab and return to the terminal.</p></body></html>",
 63→				{ headers: { "Content-Type": "text/html" } },
 64→			);
 65→		},
 66→	});
 67→
 68→	const callbackUrl = `http://127.0.0.1:${server.port}/callback`;
 69→	const loginUrl = `${flags.webUrl}?cli_callback=${encodeURIComponent(callbackUrl)}&state=${state}`;
 70→
 71→	p.log.info(`If the browser doesn't open, visit:\n${loginUrl}`);
 72→
 73→	// Open browser
 74→	if (process.platform === "win32") {
 75→		Bun.spawn(["cmd", "/c", "start", "", loginUrl], {
 76→			stdout: "ignore",
 77→			stderr: "ignore",
 78→		});
 79→	} else {
 80→		const opener = process.platform === "darwin" ? "open" : "xdg-open";
 81→		Bun.spawn([opener, loginUrl], { stdout: "ignore", stderr: "ignore" });
 82→	}
 83→
 84→	// Wait for callback with timeout
 85→	const timeout = setTimeout(() => {
 86→		rejectCallback(new Error("Login timed out after 120 seconds"));
 87→	}, CALLBACK_TIMEOUT_MS);
 88→
 89→	const spin = p.spinner();
 90→	spin.start("Waiting for browser authentication...");
 91→
 92→	let token: string;
 93→	try {
 94→		token = await tokenPromise;
 95→	} catch (error) {
 96→		clearTimeout(timeout);
 97→		server.stop();
 98→		spin.stop("Authentication failed");
 99→		p.log.error(error instanceof Error ? error.message : String(error));
100→		process.exitCode = 1;
101→		return;
102→	}
103→	clearTimeout(timeout);
104→	server.stop();
105→
106→	spin.message("Validating token...");
107→
108→	// Validate token via /rpc/me
109→	const meResponse = await fetch(`${flags.apiBase}/rpc/me`, {
110→		method: "POST",
111→		headers: {
112→			"Content-Type": "application/json",
113→			Authorization: `Bearer ${token}`,
114→		},
115→		body: JSON.stringify({}),
116→	});
117→
118→	if (!meResponse.ok) {
119→		spin.stop("Token validation failed");
120→		p.log.error("Login failed: token validation failed");
121→		process.exitCode = 1;
122→		return;
123→	}
124→
125→	const body = (await meResponse.json()) as {
126→		json: { id: string; email: string; name: string };
127→	};
128→
129→	saveCredentials(token, flags.apiBase);
130→	spin.stop("Authenticated");
131→	p.log.success(`Logged in as ${body.json.name} (${body.json.email})`);
132→	p.outro("Done!");
133→}
134→
135→export const loginCommand = buildCommand({
136→	loader: async () => ({ default: runLogin }),
137→	parameters: {
138→		flags: {
139→			apiBase: {
140→				kind: "parsed",
141→				parse: String,
142→				brief: "API server base URL",
143→				default: DEFAULT_API_BASE,
144→			},
145→			webUrl: {
146→				kind: "parsed",
147→				parse: String,
148→				brief: "Web app URL for authentication",
149→				default: DEFAULT_WEB_URL,
150→			},
151→		},
152→	},
153→	docs: {
154→		brief: "Authenticate with the Rudel API via browser login",
155→	},
156→});
