 40→function hasRealClaudeSessions(): boolean {
 41→	if (!existsSync(CLAUDE_PROJECTS_DIR)) return false;
 42→	try {
 43→		for (const dir of readdirSync(CLAUDE_PROJECTS_DIR)) {
 44→			try {
 45→				const files = readdirSync(join(CLAUDE_PROJECTS_DIR, dir));
 46→				if (
 47→					files.some(
 48→						(f) =>
 49→							f.endsWith(".jsonl") &&
 50→							!f.startsWith("agent-") &&
 51→							f !== "sessions-index.json",
 52→					)
 53→				)
 54→					return true;
 55→			} catch {
 56→				continue;
 57→			}
 58→		}
 59→	} catch {
 60→		/* dir not readable */
 61→	}
 62→	return false;
 63→}
