 77→/**
 78→ * Find a real session ID from ~/.claude/projects/ for integration tests.
 79→ */
 80→async function findRealSessionId(): Promise<string> {
 81→	const sessionsBase = join(homedir(), ".claude", "projects");
 82→	const projectDirs = await readdir(sessionsBase);
 83→
 84→	for (const dir of projectDirs) {
 85→		const fullDir = join(sessionsBase, dir);
 86→		const files = await readdir(fullDir).catch(() => [] as string[]);
 87→		const sessionFile = files.find(
 88→			(f) =>
 89→				f.endsWith(".jsonl") &&
 90→				!f.startsWith("agent-") &&
 91→				f !== "sessions-index.json",
 92→		);
 93→		if (sessionFile) {
 94→			return sessionFile.replace(/\.jsonl$/, "");
 95→		}
 96→	}
 97→
 98→	throw new Error("No real session found in ~/.claude/projects/");
 99→}
